96	// SetNodeAffinityArchRequirement wraps the logic to set the nodeAffinity for the pod.
97	// It verifies first that no nodeSelector field is set for the kubernetes.io/arch label.
98	// Then, it computes the intersection of the architectures supported by the images used by the pod via pod.getArchitecturePredicate.
99	// Finally, it initializes the nodeAffinity for the pod and set it to the computed requirement via the pod.setRequiredArchNodeAffinity method.
100	func (pod *Pod) SetNodeAffinityArchRequirement(pullSecretDataList [][]byte) (bool, error) {
101		if pod.isNodeSelectorConfiguredForArchitecture() {
102			pod.publishIgnorePod()
103			return false, nil
104		}
105		requirement, err := pod.getArchitecturePredicate(pullSecretDataList)
106		if err != nil {
107			return false, err
108		}
109		pod.EnsureNoLabel(utils.ImageInspectionErrorLabel)
110		if len(requirement.Values) == 0 {
111			pod.PublishEvent(corev1.EventTypeNormal, NoSupportedArchitecturesFound, NoSupportedArchitecturesFoundMsg)
112		}
113		pod.ensureArchitectureLabels(requirement)
114	
115		if pod.Spec.Affinity == nil {
116			pod.Spec.Affinity = &corev1.Affinity{}
117		}
118	
119		if pod.Spec.Affinity.NodeAffinity == nil {
120			pod.Spec.Affinity.NodeAffinity = &corev1.NodeAffinity{}
121		}
122	
123		if pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution == nil {
124			pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution = &corev1.NodeSelector{}
125		}
126	
127		pod.setRequiredArchNodeAffinity(requirement)
128		pod.PublishEvent(corev1.EventTypeNormal, ArchitectureAwareNodeAffinitySet,
129			ArchitecturePredicateSetupMsg+fmt.Sprintf("{%s}", strings.Join(requirement.Values, ", ")))
130		return true, nil
131	}
