133	// setRequiredArchNodeAffinity sets the node affinity for the pod to the given requirement based on the rules in
134	// the sig-scheduling's KEP-3838: https://github.com/kubernetes/enhancements/tree/master/keps/sig-scheduling/3838-pod-mutable-scheduling-directives.
135	func (pod *Pod) setRequiredArchNodeAffinity(requirement corev1.NodeSelectorRequirement) {
136		// the .requiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms are ORed
137		if len(pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms) == 0 {
138			// We create a new array of NodeSelectorTerm of length 1 so that we can always iterate it in the next.
139			pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms = make([]corev1.NodeSelectorTerm, 1)
140		}
141		nodeSelectorTerms := pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms
142	
143		// The expressions within the nodeSelectorTerms are ANDed.
144		// Therefore, we iterate over the nodeSelectorTerms and add an expression to each of the terms to verify the
145		// kubernetes.io/arch label has compatible values.
146		// Note that the NodeSelectorTerms will always be long at least 1, because we (re-)created it with size 1 above if it was nil (or having 0 length).
147		var skipMatchExpressionPatch bool
148		for i := range nodeSelectorTerms {
149			skipMatchExpressionPatch = false
150			if nodeSelectorTerms[i].MatchExpressions == nil {
151				nodeSelectorTerms[i].MatchExpressions = make([]corev1.NodeSelectorRequirement, 0, 1)
152			}
153			// Check if the nodeSelectorTerm already has a matchExpression for the kubernetes.io/arch label.
154			// if yes, we ignore to add it.
155			for _, expression := range nodeSelectorTerms[i].MatchExpressions {
156				if expression.Key == requirement.Key {
157					skipMatchExpressionPatch = true
158					break
159				}
160			}
161			// if skipMatchExpressionPatch is true, we skip to add the matchExpression so that conflictual matchExpressions provided by the user are not overwritten.
162			if !skipMatchExpressionPatch {
163				nodeSelectorTerms[i].MatchExpressions = append(nodeSelectorTerms[i].MatchExpressions, requirement)
164			}
165		}
166		// if the nodeSelectorTerms were patched at least once, we set the nodeAffinity label to the set value, to keep
167		// track of the fact that the nodeAffinity was patched by the operator.
168		pod.EnsureLabel(utils.NodeAffinityLabel, utils.NodeAffinityLabelValueSet)
169	}
