263	// trackAffinitySource tracks which config sources attempted to set affinity for which architectures.
264	// This information is later used to build the annotation showing the full audit trail.
265	func (pod *Pod) trackAffinitySource(arch string, weight int32, source string, applied bool) {
266		// Get existing annotation or start fresh
267		existingAnnotation := ""
268		if pod.Annotations != nil {
269			existingAnnotation = pod.Annotations[utils.PreferredNodeAffinitySourcesAnnotation]
270		}
271	
272		// Format: arch:weight:source or arch:weight:source:skipped
273		var newEntry string
274		if applied {
275			newEntry = fmt.Sprintf("%s:%d:%s", arch, weight, source)
276		} else {
277			newEntry = fmt.Sprintf("%s:%d:%s:skipped", arch, weight, source)
278		}
279	
280		// Check if this entry already exists to avoid duplicates on retries
281		if existingAnnotation != "" {
282			entries := strings.Split(existingAnnotation, ",")
283			for _, entry := range entries {
284				if entry == newEntry {
285					// Entry already exists, don't add it again
286					return
287				}
288			}
289		}
290	
291		// Append to existing annotation with comma separator
292		if existingAnnotation == "" {
293			pod.EnsureAnnotation(utils.PreferredNodeAffinitySourcesAnnotation, newEntry)
294		} else {
295			pod.EnsureAnnotation(utils.PreferredNodeAffinitySourcesAnnotation, existingAnnotation+","+newEntry)
296		}
297	}
