325	func (pod *Pod) getArchitecturePredicate(pullSecretDataList [][]byte) (corev1.NodeSelectorRequirement, error) {
326		architectures, err := pod.intersectImagesArchitecture(pullSecretDataList)
327		// if an error occurs, we return an empty NodeSelectorRequirement and the error.
328		if err != nil {
329			return corev1.NodeSelectorRequirement{}, err
330		}
331	
332		if len(architectures) == 0 {
333			return corev1.NodeSelectorRequirement{
334				Key:      utils.NoSupportedArchLabel,
335				Operator: corev1.NodeSelectorOpExists,
336			}, nil
337		}
338		return corev1.NodeSelectorRequirement{
339			Key:      utils.ArchLabel,
340			Operator: corev1.NodeSelectorOpIn,
341			Values:   architectures,
342		}, nil
343	}
