389	func (pod *Pod) maxRetries() bool {
390		if pod.Labels == nil {
391			return false
392		}
393		v, err := strconv.ParseInt(pod.Labels[utils.ImageInspectionErrorCountLabel], 10, 32)
394		if err != nil {
395			return true
396		}
397		return v >= MaxRetryCount
398	}
