490	func (pod *Pod) publishIgnorePod() {
491		log := ctrllog.FromContext(pod.Ctx())
492		log.V(1).Info("The pod has the nodeSelector or all the nodeAffinityTerms set for the kubernetes.io/arch label. Ignoring the pod...")
493		pod.EnsureLabel(utils.NodeAffinityLabel, utils.LabelValueNotSet)
494		pod.PublishEvent(corev1.EventTypeNormal, ArchitecturePredicatesConflict, ArchitecturePredicatesConflictMsg)
495	}
